class RabbitMQAPI:
    def __init__(self, base_url: str, username: str, password: str, verify_tls: bool = True, timeout: int = 15):
        self.base_url = base_url.rstrip("/")
        self.auth = (username, password)
        self.verify_tls = verify_tls
        self.timeout = timeout
        self.session = requests.Session()
        self.session.auth = self.auth
        self.session.headers.update({"Content-Type": "application/json"})

    def _url(self, path: str) -> str:
        return f"{self.base_url}{path}"

    def _request(self, method: str, path: str, expected: Tuple[int, ...] = (200, 201, 204), json_body=None):
        response = self.session.request(
            method=method,
            url=self._url(path),
            json=json_body,
            timeout=self.timeout,
            verify=self.verify_tls,
        )
        if response.status_code not in expected:
            try:
                body = response.json()
            except Exception:
                body = response.text
            raise RuntimeError(
                f"RabbitMQ API request failed: {method} {path} -> {response.status_code} {response.reason}; body={body}"
            )
        return response

    @staticmethod
    def _quote(value: str) -> str:
        return urllib.parse.quote(value, safe="")

    def health_check(self):
        self._request("GET", "/api/overview", expected=(200,))

    def ensure_vhost(self, vhost: str, tracing: bool = False, description: str = ""):
        payload = {"tracing": tracing, "description": description, "tags": []}
        self._request("PUT", f"/api/vhosts/{self._quote(vhost)}", expected=(201, 204), json_body=payload)

