def load_config(path: str) -> List[TenantConfig]:
    with open(path, "r", encoding="utf-8") as f:
        raw = json.load(f)

    tenants_raw = raw.get("tenants", raw if isinstance(raw, list) else [])
    tenants: List[TenantConfig] = []

    for tenant in tenants_raw:
        users = []
        for user in tenant.get("users", []):
            perms_raw = user.get("permissions", {})
            permissions = Permission(
                configure=perms_raw.get("configure", ".*"),
                write=perms_raw.get("write", ".*"),
                read=perms_raw.get("read", ".*"),
            )
            topic_permissions = [
                TopicPermission(
                    exchange=tp["exchange"],
                    write=tp.get("write", ".*"),
                    read=tp.get("read", ".*"),
                )
                for tp in user.get("topic_permissions", [])
            ]
            users.append(
                UserConfig(
                    name=user["name"],
                    password=user.get("password"),
                    tags=user.get("tags", []),
                    permissions=permissions,
                    topic_permissions=topic_permissions,
                )
            )

        tenants.append(
            TenantConfig(
                app=tenant.get("app", tenant["vhost"]),
                vhost=tenant["vhost"],
                users=users,
                tracing=tenant.get("tracing", False),
                description=tenant.get("description", ""),
            )
        )

    return tenants


def build_arg_parser():
    parser = argparse.ArgumentParser(
        description="Configure RabbitMQ virtual hosts, users, and permissions using the Management HTTP API."
    )
    parser.add_argument(
        "--api-url",
        default=os.getenv("RABBITMQ_API_URL", "http://localhost:15672"),
        help="RabbitMQ Management API base URL, e.g. http://localhost:15672",
    )
    parser.add_argument(
        "--admin-user",
        default=os.getenv("RABBITMQ_ADMIN_USER", "guest"),
        help="RabbitMQ admin username",
    )
    parser.add_argument(
        "--admin-password",
        default=os.getenv("RABBITMQ_ADMIN_PASSWORD", "guest"),
        help="RabbitMQ admin password",
    )
    parser.add_argument(
        "--config",
        required=True,
        help="Path to JSON config file describing tenants, vhosts, users, and permissions",
    )
    parser.add_argument(
        "--insecure",
        action="store_true",
        help="Disable TLS certificate verification",
    )
    parser.add_argument(
        "--timeout",
        type=int,
        default=int(os.getenv("RABBITMQ_API_TIMEOUT", "15")),
        help="HTTP request timeout in seconds",
    )
    return parser


def configure_rabbitmq(api: RabbitMQAPI, tenants: List[TenantConfig]):
    for tenant in tenants:
        print(f"Ensuring vhost '{tenant.vhost}' for app '{tenant.app}'")
        api.ensure_vhost(tenant.vhost, tracing=tenant.tracing, description=tenant.description)

        for user in tenant.users:
            print(f"Ensuring user '{user.name}'")
            api.ensure_user(user.name, user.password, user.tags)

            print(f"Setting permissions for user '{user.name}' on vhost '{tenant.vhost}'")
            api.set_permissions(tenant.vhost, user.name, user.permissions)

            for tp in user.topic_permissions:
                print(
                    f"Setting topic permissions for user '{user.name}' on vhost '{tenant.vhost}' "
                    f"exchange '{tp.exchange}'"
                )
                api.set_topic_permissions(tenant.vhost, user.name, tp)


def main():
    parser = build_arg_parser()
    args = parser.parse_args()

    try:
        tenants = load_config(args.config)
        if not tenants:
            raise ValueError("No tenants found in config file")

        api = RabbitMQAPI(
            base_url=args.api_url,
            username=args.admin_user,
            password=args.admin_password,
            verify_tls=not args.insecure,
            timeout=args.timeout,
        )
        api.health_check()
        configure_rabbitmq(api, tenants)
        print("RabbitMQ configuration completed successfully")
    except Exception as e:
        print(f"ERROR: {e}", file=sys.stderr)
        sys.exit(1)


if __name__ == "__main__":
    main()